'function render (',
'            p_dynamic_action in apex_plugin.t_dynamic_action,',
'            p_plugin         in apex_plugin.t_plugin',
'            ) ',
'            return apex_plugin.t_dynamic_action_render_result',
'is',
'    l_result                apex_plugin.t_dynamic_action_render_result;',
'',
'begin',
'',
'        l_result.ajax_identifier    := apex_plugin.get_ajax_identifier;',
'',
'        l_result.javascript_function :=',
'        ''function(){ MasterSwitch.init('' ||',
unistr('            -- 1) ZAWSZE przeka\017C kontekst DA jako pierwszy argument (this)'),
'            ''this,'' ||',
unistr('            -- 2) Kolejne parametry: dok\0142adnie takie jak w sygnaturze JS'),
'            apex_javascript.add_value( p_dynamic_action.attribute_01, true  ) ||                                        -- Master Selector',
'            apex_javascript.add_value( p_dynamic_action.attribute_02, true  ) ||                                        -- Group Selector',
'            apex_javascript.add_value( coalesce(p_dynamic_action.attribute_03, ''input[type="checkbox"]''), true ) ||     -- Checkbox Selector',
unistr('            -- Y/N booleany \2013 przeka\017Cmy je jako pojedyncze znaki (string), a w JS zmapujemy na boolean.'),
'            apex_javascript.add_value( case when p_dynamic_action.attribute_04 = ''N'' then ''N'' else ''Y'' end, true ) ||   -- Exclude Disabled',
'            apex_javascript.add_value( case when p_dynamic_action.attribute_05 = ''Y'' then ''Y'' else ''N'' end, true ) ||   -- Propagate Change',
'            apex_javascript.add_value( case when p_dynamic_action.attribute_06 = ''N'' then ''N'' else ''Y'' end, true ) ||   -- Initialize On Load',
'            apex_javascript.add_value( coalesce( p_dynamic_action.attribute_07, ''is-indeterminate''), true ) ||          -- Indeterminate CSS Class',
'            apex_javascript.add_value(nvl(p_dynamic_action.attribute_08, ''''), false ) ||                                -- Generate Event Name',
'        ''); }'';',
'',
'    return l_result;',
'',
'end render;'))
,p_api_version=>1
,p_render_function=>'render'
,p_standard_attributes=>'ITEM'
